import org.owasp.encoder.Encode;

public class XSSFixedCode {
    public static void main(String[] args) {
        // Simulating user input
        String userInput = "<script>alert('XSS Vulnerability')</script>";

        // Properly handling user input by encoding it before outputting to the HTML response
        String output = "<p>User input: " + Encode.forHtml(userInput) + "</p>";

        // Displaying the output in the console
        System.out.println(output);
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
